}
@keyframes darma-loader-uiverse-gradient-flip-squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }

.darma-loader-uiverse-neon-orbit {
      position: relative;
      display: inline-block;
      width: 64px;
      height: 64px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #f59e0b) 24%, transparent);
    }
    .darma-loader-uiverse-neon-orbit i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-uiverse-neon-orbit-orbit 1.1s linear infinite;
    }
    .darma-loader-uiverse-neon-orbit i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #f59e0b);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #f59e0b) 45%, transparent);
    }
    .darma-loader-uiverse-neon-orbit i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-neon-orbit i:nth-child(2) { animation-delay: -0.37s; }
.darma-loader-uiverse-neon-orbit i:nth-child(3) { animation-delay: -0.73s; }
    @keyframes darma-loader-uiverse-neon-orbit-orbit { to { transform: rotate(360deg); } }

